+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+/** A boundary for a window frame. */
+export interface WindowFrameBoundary {
+	readonly sql: SQL;
+	readonly position: number;
+}
+
+function boundary(value: string, position: number): WindowFrameBoundary {
+	return { sql: sql.raw(value), position };
+}
+
+export const unboundedPreceding = boundary('unbounded preceding', Number.NEGATIVE_INFINITY);
+export const currentRow = boundary('current row', 0);
+export const unboundedFollowing = boundary('unbounded following', Number.POSITIVE_INFINITY);
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): WindowFrameBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+	return boundary(`${value} ${name}`, name === 'preceding' ? -value : value);
+}
+
+/** Creates a frame boundary relative to the current row. */
+export function preceding(value: number): WindowFrameBoundary {
+	return positionalBoundary('preceding', value);
+}
+
+/** Creates a frame boundary relative to the current row. */
+export function following(value: number): WindowFrameBoundary {
+	return positionalBoundary('following', value);
+}
+
+export interface WindowFrame {
+	readonly sql: SQL;
+}
+
+export interface WindowFrameSpec {
+	from: WindowFrameBoundary;
+	to: WindowFrameBoundary;
+}
+
+function frame(kind: 'rows' | 'range', spec: WindowFrameSpec): WindowFrame {
+	if (spec.from.position > spec.to.position) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { sql: sql`${sql.raw(kind)} between ${spec.from.sql} and ${spec.to.sql}` };
+}
+
+/** Creates a ROWS window frame. */
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return frame('rows', spec);
+}
+
+/** Creates a RANGE window frame. */
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined
+		? undefined
+		: sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`;
+	const orderBy = spec.orderBy === undefined
+		? undefined
+		: sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`;
+	return sql.join([partitionBy, orderBy, spec.frame?.sql].filter((part): part is SQL => part !== undefined), sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function functionCall<T>(name: string, args: (SQLWrapper | number | undefined)[]): WindowFunction<T> {
+	const chunks: SQL[] = [];
+	for (const arg of args) {
+		if (arg === undefined) continue;
+		// Positional arguments are SQL syntax, never query parameters.
+		chunks.push(typeof arg === 'number' ? sql.raw(String(arg)) : arg.getSQL());
+	}
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(chunks, sql`, `)})`);
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return functionCall('row_number', []); }
+export function rank(): WindowFunction<number> { return functionCall('rank', []); }
+export function denseRank(): WindowFunction<number> { return functionCall('dense_rank', []); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return functionCall('ntile', [buckets]); }
+export function percentRank(): WindowFunction<number> { return functionCall('percent_rank', []); }
+export function cumeDist(): WindowFunction<number> { return functionCall('cume_dist', []); }
+
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<defaultValue extends undefined ? Value<T> | null : Value<T>> { return functionCall('lag', [expression, offset, defaultValue]) as any; }
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<defaultValue extends undefined ? Value<T> | null : Value<T>> { return functionCall('lead', [expression, offset, defaultValue]) as any; }
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return functionCall('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return functionCall('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<Value<T> | null> { positiveInteger('nthValue', nth); return functionCall('nth_value', [expression, nth]); }
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return functionCall('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return functionCall('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return functionCall('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return functionCall('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return functionCall('count', [expression ?? sql.raw('*')]); }
