+
+describe('window expressions', () => {
+	it('builds inline windows without parameters for positional arguments', () => {
+		const query = db.select({
+			rank: rowNumber().over({ partitionBy: users.team, orderBy: users.name, frame: rows({ from: unboundedPreceding, to: currentRow }) }),
+			bucket: ntile(0 + 2).over({}),
+			previous: lag(users.name, 0).over({ orderBy: users.name }),
