+		expect(query.toSQL()).toEqual({
+			sql: 'select row_number() over (partition by "users"."team" order by "users"."name" rows between unbounded preceding and current row), ntile(2) over (), lag("users"."name", 0) over (order by "users"."name"), sum("users"."name") over (range between 1 preceding and 1 following), count(*) over () from "users"',
